### Clear Recursive Algorithm (Standard Interview Style)

Assume we have global/intended output node `ans`:

```python
def find_lca(root, p, q):
    # We'll use a sentinel value 'done' to indicate that both targets are found
    done = [False]

    def dfs(node):
        if not node:
            return None

        left = dfs(node.left)
        right = dfs(node.right)

        # Check if current node is one of the targets
        cur_is_target = None
        if node == p:
            cur_is_target = node
        elif node == q:
            cur_is_target = node

        # Count how many targets we've seen in this recursion branch
        count = 0
        if cur_is_target:
            count += 1

        if left:
            count |= 1
        if right:
            count |= 1

        # If we see at least one target, store it
        res = None
        if left:
            res = left
        if right:
            # If left didn't return anything but right did, that could be final
            # But we need to ensure we don't overwrite earlier LCA decisions.
